268	// CapabilitiesViaService returns HarnessCapabilities for the named harness by
269	// querying the service's ListHarnesses and (best-effort) the harness registry.
270	// It is the production replacement for Runner.Capabilities.
271	func CapabilitiesViaService(ctx context.Context, workDir, harnessName string) (*HarnessCapabilities, error) {
272		if ctx == nil {
273			ctx = context.Background()
274		}
275		svc, err := NewServiceFromWorkDir(workDir)
276		if err != nil {
277			return nil, fmt.Errorf("agent: build service: %w", err)
278		}
279		infos, err := svc.ListHarnesses(ctx)
280		if err != nil {
281			return nil, fmt.Errorf("agent: list harnesses: %w", err)
282		}
283		var info *agentlib.HarnessInfo
284		for i := range infos {
285			if infos[i].Name == harnessName {
286				info = &infos[i]
287				break
288			}
289		}
290		if info == nil {
291			return nil, fmt.Errorf("agent: unknown harness: %s", harnessName)
292		}
293	
294		// Pull binary and reasoning-level metadata from the local registry — the
295		// service does not expose these directly today.
296		registry := newHarnessRegistry()
297		harness, _ := registry.Get(harnessName)
298	
299		caps := &HarnessCapabilities{
300			Harness:             info.Name,
301			Available:           info.Available,
302			Binary:              harness.Binary,
303			Path:                info.Path,
304			Surface:             harness.Surface,
305			CostClass:           info.CostClass,
306			IsLocal:             info.IsLocal,
307			ExactPinSupport:     info.ExactPinSupport,
308			SupportsEffort:      len(info.SupportedReasoning) > 0 || harness.EffortFlag != "",
309			SupportsPermissions: len(info.SupportedPermissions) > 0 || len(harness.PermissionArgs) > 0,
310		}
311		if len(info.SupportedReasoning) > 0 {
312			caps.ReasoningLevels = append([]string{}, info.SupportedReasoning...)
313		} else if len(harness.ReasoningLevels) > 0 {
314			caps.ReasoningLevels = append([]string{}, harness.ReasoningLevels...)
315		}
316	
317		if harness.DefaultModel != "" {
318			caps.Model = harness.DefaultModel
319			caps.Models = []string{harness.DefaultModel}
320		}
321	
322		// Profile mappings come from the local model catalog because the service
323		// does not surface a per-tier resolution endpoint today.
324		if harness.Surface != "" {
325			cat := BuiltinCatalog
326			for _, profile := range []string{"cheap", "fast", "smart"} {
327				if m, ok := cat.Resolve(profile, harness.Surface); ok {
328					if caps.ProfileMappings == nil {
329						caps.ProfileMappings = make(map[string]string)
330					}
331					caps.ProfileMappings[profile] = m
332				}
333			}
334		}
335		return caps, nil
336	}
