338	// TestProviderConnectivityViaService runs a HealthCheck against the named
339	// harness and translates the result into a ProviderStatus. It is the
340	// production replacement for Runner.TestProviderConnectivity.
341	func TestProviderConnectivityViaService(ctx context.Context, workDir, harnessName string, timeout time.Duration) ProviderStatus {
342		status := ProviderStatus{Reachable: false}
343		if ctx == nil {
344			ctx = context.Background()
345		}
346		if harnessName == "virtual" || harnessName == "agent" {
347			status.Reachable = true
348			status.CreditsOK = true
349			return status
350		}
351		svc, err := NewServiceFromWorkDir(workDir)
352		if err != nil {
353			status.Error = err.Error()
354			return status
355		}
356		if timeout > 0 {
357			var cancel context.CancelFunc
358			ctx, cancel = context.WithTimeout(ctx, timeout)
359			defer cancel()
360		}
361		if err := svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: harnessName}); err != nil {
362			errStr := strings.ToLower(err.Error())
363			status.Error = err.Error()
364			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
365				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
366				status.CreditsOK = false
367			}
368			return status
369		}
370		status.Reachable = true
371		status.CreditsOK = true
372		return status
373	}
