181	// --- Pattern 2: composite literal of legacy options type ------------------
182	
183	func checkLegacyComposite(pass *analysis.Pass, cl *ast.CompositeLit, report func(token.Pos, string)) {
184		t := pass.TypesInfo.TypeOf(cl)
185		if t == nil {
186			return
187		}
188		if ptr, ok := t.(*types.Pointer); ok {
189			t = ptr.Elem()
190		}
191		named, ok := t.(*types.Named)
192		if !ok {
193			return
194		}
195		obj := named.Obj()
196		if obj == nil {
197			return
198		}
199		if !legacyOptionsTypes[obj.Name()] {
200			return
201		}
202		// Scope to types declared in cli/internal/agent/ — avoids false-
203		// positives if some unrelated package happens to use the same name.
204		if obj.Pkg() == nil || !pkgPathHasSuffix(obj.Pkg().Path(), agentPkgSuffixes) {
205			return
206		}
207		report(cl.Pos(),
208			"runtimelint: composite literal of legacy options type "+obj.Name()+" — these types are retired; use the *Runtime + ResolvedConfig pair instead (SD-024 §Stage 4 / TD-024 §Lint rule)")
209	}
